let cur   = 0;


let STATE    = 'typing';
let typeGen    = 0;

let dissolveGen = 0;

let dissolved = false;

let zoomP    = 0;

let ZOOM_IN_SPD_CUR = 0.006;

const ZOOM_IN_SPD   = 0.006;
const ZOOM_OUT_SPD  = 0.07;
const ZOOM_DIST     = 75;

const WAIT_DURATION = 4000;

let waitTimer   = null;
let typeTimer   = null;

